#include<bits/stdc++.h>
using namespace std;
bool vis[10005];
int A[10005],a[10005],k,n,m,ans=0;
vector<int> b[10005];
void dfs(int x){
	vis[x]=1,A[x]++;
	for(int i=0;i<b[x].size();i++)if(!vis[b[x][i]])dfs(b[x][i]);
}
int main(void){
    int u,v;
    cin>>k>>n>>m;
    for(int i=1;i<=k;i++)cin>>a[i];
    for(int i=1;i<=m;i++)cin>>u>>v,b[u].push_back(v);
    for(int i=1;i<=k;i++){memset(vis,false,sizeof(vis));dfs(a[i]);}
    for(int i=1;i<=n;i++)ans+=(A[i]==k);
    cout<<ans;
    return false;
}
